import SwiftUI
import AIUsagesTrackersLib

struct SettingsView: View {
    let launchAtLoginService: any LaunchAtLoginManaging

    var body: some View {
        // Access sharedPreferences directly so SwiftUI can observe the concrete
        // @Observable UserDefaultsAppPreferences type instead of the existential protocol.
        let preferences = AppDelegate.sharedPreferences

        return TabView {
            GeneralSettingsView(
                preferences: preferences,
                launchAtLoginService: launchAtLoginService
            )
            .tabItem { Label("General", systemImage: "gearshape") }

            MenubarHintSettingsView(preferences: preferences)
                .tabItem { Label("Menubar hint", systemImage: "menubar.rectangle") }

            ChartSettingsView(preferences: preferences)
                .tabItem { Label("Charts", systemImage: "chart.xyaxis.line") }

            UpdatesSettingsView(
                preferences: preferences,
                updateState: AppDelegate.sharedUpdateState
            )
            .tabItem { Label("Updates", systemImage: "arrow.down.circle") }

            // AssistantsSettingsView(preferences: preferences)
            //     .tabItem { Label("Assistants", systemImage: "sparkles") }
        }
        .frame(minWidth: 680, idealWidth: 720, minHeight: 750, idealHeight: 800)
    }
}

import SwiftUI
import AIUsagesTrackersLib

/// Scrollable popover anchored to the menu bar item; uses LazyVStack + maxHeight
/// so the popover does not stretch unboundedly when many accounts are present.
struct UsageDetailsView: View {
    let store: UsageStore
    let refreshState: RefreshState
    let historyReader: UsageHistoryReader
    let updateState: UpdateState
    let onRefresh: () async -> Void
    let onOpenSettings: () -> Void
    let onQuit: () -> Void
    let onInstallUpdate: () -> Void
    let onRestartUpdate: () -> Void
    let onSkipUpdate: () -> Void
    let onLaterUpdate: () -> Void

    @State private var contentMode: PopoverContentMode = .list
    @State private var selectedHistoryWindow: UsageHistoryTimeWindow = .twentyFourHours
    @State private var historySnapshot: UsageHistorySnapshot = .empty
    @State private var historyReferenceDate = Date()
    @State private var historyWindowOffset: Int = 0
    @State private var isLoadingHistory = false
    @State private var showTesterFeedbackSheet = false

    /// Resolved at app launch from the bundle's Info.plist trio. Non-nil
    /// only on tester DMGs; absent on stable releases by construction.
    private let testerFeedbackContext: TesterFeedbackContext? = TesterFeedbackContext.resolved

    private static let popoverWidth: CGFloat = 320
    private static let maxScreenHeightRatio: CGFloat = 0.9
    private static let fallbackScreenHeight: CGFloat = 800
